// Benchmarking code for frogemm kernels
// Code Generated by GPT 5.3 Codex
// Verified by author::datavorous

// Usage: make && ./bench/bench M N K [kernel_name]
// Example: ./bench/bench 512 512 512 naive

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include "frogemm.h"

typedef void (*gemm_fn)(int M, int N, int K, float *A, float *B, float *C);

typedef struct {
    const char *name;
    gemm_fn fn;
} kernel_entry;

static int cmp_double(const void *a, const void *b) {
    const double da = *(const double *)a;
    const double db = *(const double *)b;
    if (da < db) return -1;
    if (da > db) return 1;
    return 0;
}

static double median_us_for_kernel(gemm_fn fn, int M, int N, int K, float *A, float *B, float *C, int runs, int warmup) {
    double timings[64];
    double usable[64];

    if (runs > 64 || warmup >= runs) {
        return -1.0;
    }

    for (int r = 0; r < runs; r++) {
        clock_t start = clock();
        fn(M, N, K, A, B, C);
        clock_t end = clock();
        timings[r] = (double)(end - start) * 1000000.0 / CLOCKS_PER_SEC;
    }

    for (int i = 0; i < runs - warmup; i++) {
        usable[i] = timings[i + warmup];
    }
    qsort(usable, runs - warmup, sizeof(double), cmp_double);

    if ((runs - warmup) % 2 == 0) {
        int m = (runs - warmup) / 2;
        return (usable[m - 1] + usable[m]) / 2.0;
    }
    return usable[(runs - warmup) / 2];
}

static void print_kernel_result(const char *name, double median_us, int M, int N, int K, double peak_gflops, int runs, int warmup) {
    const double time_seconds = median_us * 1e-6;
    const double flops = 2.0 * (double)M * (double)N * (double)K;
    const double efficiency = flops / (time_seconds * peak_gflops * 1e9);

    printf("[%s] median time (%d runs, excluding first %d): %f microseconds\n", name, runs, warmup, median_us);
    printf("[%s] efficiency (vs %.1f GFLOPS peak): %.6f (%.2f%%)\n", name, peak_gflops, efficiency, efficiency * 100.0);
}

int main(int argc, char *argv[]) {
    const int runs = 10;
    const int warmup = 2;
    const double peak_gflops = 540.0; // notes/device.md turbo peak F32

    // IMPORTANT: keep this list in sync with the kernels implemented in src/*.c
    // declared in include/frogemm.h
    kernel_entry kernels[] = {
        {"naive", frogemm_naive},
        {"tiled", frogemm_tiled},
    };

    const int kernel_count = (int)(sizeof(kernels) / sizeof(kernels[0]));

    if (argc != 4 && argc != 5) {
        printf("Usage: %s M N K [kernel_name]\n", argv[0]);
        return -1;
    }

    int M = atoi(argv[1]);
    int N = atoi(argv[2]);
    int K = atoi(argv[3]);
    const char *selected_kernel = (argc == 5) ? argv[4] : NULL;

    float *A = (float*)malloc(M * K * sizeof(float));
    float *B = (float*)malloc(K * N * sizeof(float));
    float *C = (float*)malloc(M * N * sizeof(float));
    if (A == NULL || B == NULL || C == NULL) {
        printf("Allocation failed\n");
        free(A);
        free(B);
        free(C);
        return -1;
    }

    for (int i = 0; i < M * K; i++) {
        A[i] = (float)rand() / RAND_MAX;
    }
    for (int i = 0; i < K * N; i++) {
        B[i] = (float)rand() / RAND_MAX;
    }

    if (selected_kernel != NULL) {
        int found = 0;
        for (int i = 0; i < kernel_count; i++) {
            if (strcmp(selected_kernel, kernels[i].name) == 0) {
                double median = median_us_for_kernel(kernels[i].fn, M, N, K, A, B, C, runs, warmup);
                print_kernel_result(kernels[i].name, median, M, N, K, peak_gflops, runs, warmup);
                found = 1;
                break;
            }
        }
        if (!found) {
            printf("Unknown kernel: %s\n", selected_kernel);
            printf("Available kernels:");
            for (int i = 0; i < kernel_count; i++) {
                printf(" %s", kernels[i].name);
            }
            printf("\n");
            free(A);
            free(B);
            free(C);
            return -1;
        }
    } else {
        for (int i = 0; i < kernel_count; i++) {
            double median = median_us_for_kernel(kernels[i].fn, M, N, K, A, B, C, runs, warmup);
            print_kernel_result(kernels[i].name, median, M, N, K, peak_gflops, runs, warmup);
        }
    }

    free(A);
    free(B);
    free(C);

    return 0;
}
